#!/bin/bash`n# lib/template.sh - 简单模板引擎`n`nrender_template() {`n    local template="$1"`n    local output="$2"`n    `n    if [[ ! -f "$template" ]]; then`n        echo "Error: Template not found: $template" >&2`n        return 1`n    fi`n    `n    cp "$template" "$output"`n    `n    local var`n    while IFS= read -r line; do`n        while [[ "$line" =~ \{\{[[:space:]]*([A-Za-z_][A-Za-z0-9_]*)[[:space:]]*\}\} ]]; do`n            local var_name="${BASH_REMATCH[1]}"`n            local var_value="${!var_name}"`n            var_value="${var_value:-}"`n            line="${line//\{\{${var_name}\}\}/$var_value}"`n        done`n        echo "$line"`n    done < "$output" > "${output}.tmp"`n    `n    mv "${output}.tmp" "$output"`n}`n`nrender_nomad_config() {`n    local role="$1"`n    local output="$2"`n    local template_dir="$(dirname "$0")/../templates/nomad"`n    `n    case "$role" in`n        server)`n            render_template "$template_dir/server.hcl.tpl" "$output"`n            ;;`n        client)`n            render_template "$template_dir/client.hcl.tpl" "$output"`n            ;;`n        *)`n            echo "Error: Unknown Nomad role: $role" >&2`n            return 1`n            ;;`n    esac`n}`n